if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const body=$input.first().json.body||{};
if(body.auth_key!==$env.GDA_API_KEY_2026) return [{json:{error:'Unauthorized'}}];
return [{json:{action:body.action||'list'}}];

const rows = $input.all().map(i => i.json);
const contracts = rows.map(c => {
  const fyRev = c.fy_revenue || {};
  return {
    id: c.id,
    name: c.name,
    client: c.client,
    piid: c.piid,
    idv: c.idv,
    naics: c.naics,
    contract_type: c.contract_type,
    ceiling: parseFloat(c.ceiling) || 0,
    funded: parseFloat(c.funded) || 0,
    pop_start: c.pop_start,
    pop_end: c.pop_end,
    option_years: c.option_years,
    options_exercised: c.options_exercised,
    status: c.status,
    pm: c.pm,
    cotr: c.cotr,
    employees: parseInt(c.employees) || 0,
    location: c.location,
    description: c.description,
    key_personnel: c.key_personnel,
    ou: c.ou,
    fy_revenue: typeof fyRev === 'string' ? JSON.parse(fyRev) : fyRev
  };
});

const totalCeiling = contracts.reduce((s, c) => s + c.ceiling, 0);
const totalFunded = contracts.reduce((s, c) => s + c.funded, 0);
const totalEmployees = contracts.reduce((s, c) => s + c.employees, 0);

return [{ json: {
  status: 'ok',
  count: contracts.length,
  total_ceiling: totalCeiling,
  total_funded: totalFunded,
  total_employees: totalEmployees,
  contracts
}}];
